-- 0. 冪等のためまず削除（プレフィックス指定）
DELETE FROM birthday_messages WHERE creator_id IN (SELECT id FROM profiles WHERE id::text LIKE '10000000-%');
DELETE FROM content_comments WHERE id::text LIKE 'cc000000-%';
DELETE FROM stories WHERE creator_id IN (SELECT id FROM profiles WHERE id::text LIKE '10000000-%');
DELETE FROM live_streams WHERE creator_id IN (SELECT id FROM profiles WHERE id::text LIKE '10000000-%');
DELETE FROM auction_bids WHERE auction_id IN (SELECT id FROM request_auctions WHERE id::text LIKE 'a0000000-%');
DELETE FROM request_auctions WHERE id::text LIKE 'a0000000-%';
DELETE FROM subscription_plans WHERE creator_id IN (SELECT id FROM profiles WHERE id::text LIKE '10000000-%');

