INSERT INTO live_streams (id, creator_id, title, description, thumbnail_url, scheduled_at, stream_url, is_premium, premium_price, status, viewer_peak, created_at) VALUES
  ('11000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002', '🌸 みーちゃんの夜お話しライブ', '今日あった出来事をゆるーく話します！コメントどんどんお待ちしてます💕', 'https://picsum.photos/seed/live1/640/360', now() - interval '30 minutes', 'https://www.youtube.com/watch?v=demo', false, 0, 'live', 1247, now() - interval '1 hours'),
  ('11000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000004', '【生配信】コス試着会！リクエスト募集🎀', 'みんなのリクエストでコスプレ着替え対決🌸 投げ銭で衣装決定！', 'https://picsum.photos/seed/live2/640/360', now() - interval '15 minutes', 'https://www.youtube.com/watch?v=demo2', false, 0, 'live', 892, now() - interval '40 minutes'),
  ('11000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000001', '🎂 28歳バースデー前夜祭🎉', '誕生日の前夜を一緒に過ごしませんか？プレミアム配信！', 'https://picsum.photos/seed/live3/640/360', now() + interval '1 days', null, true, 1500, 'scheduled', 0, now() - interval '2 days'),
  ('11000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000005', 'ASMR寝落ちラジオ🌙 (耳元囁き)', '寝つきが悪い夜にどうぞ。ヘッドホン推奨。', 'https://picsum.photos/seed/live4/640/360', now() + interval '2 days', null, true, 800, 'scheduled', 0, now() - interval '1 days'),
  ('11000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000007', '雑談ゆるライブ✨', '今週のお仕事の話とか〜', 'https://picsum.photos/seed/live5/640/360', now() + interval '3 days', null, false, 0, 'scheduled', 0, now() - interval '12 hours'),
  ('11000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000010', 'メイク講座🎨', '自分のメイク手順を全部見せちゃいます', 'https://picsum.photos/seed/live6/640/360', now() + interval '5 days', null, true, 1000, 'scheduled', 0, now() - interval '6 hours'),
  ('11000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000012', 'ゲーム実況ナイト🎮', 'ホラーゲームに挑戦！絶対叫ぶ。', 'https://picsum.photos/seed/live7/640/360', now() + interval '7 days', null, false, 0, 'scheduled', 0, now() - interval '3 hours');
