INSERT INTO request_auctions (id, user_id, title, description, category, budget_min, budget_max, deadline, status, created_at) VALUES
  ('a0000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000001', '私の誕生日に動画メッセージが欲しい', '5月15日が私の誕生日です。20秒くらいのお祝い動画を作っていただけると嬉しいです。お名前は「みき」でお願いします。', 'バースデー', 3000, 8000, now() + interval '5 days', 'open', now() - interval '2 hours'),
  ('a0000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000002', '応援用のチェキ写真が欲しい', '推しと一緒の自撮りチェキを購入したいです。私の名前「ゆうき」を入れていただけたら最高です！', 'チェキ', 1500, 5000, now() + interval '7 days', 'open', now() - interval '1 days'),
  ('a0000000-0000-0000-0000-000000000003', '20000000-0000-0000-0000-000000000003', 'ASMRボイスを依頼したい', '勉強用の応援ボイスメッセージを5分くらいで作っていただきたいです。耳元で囁くスタイルで。', 'ボイス', 2000, 6000, now() + interval '10 days', 'open', now() - interval '6 hours'),
  ('a0000000-0000-0000-0000-000000000004', '20000000-0000-0000-0000-000000000004', '結婚式で使うコスプレ動画', '友人の結婚式で流す動画を作っていただきたいです。新郎新婦の名前を入れて、ナース服コスプレで30秒の動画を希望します。', 'コスプレ', 5000, 15000, now() + interval '14 days', 'open', now() - interval '12 hours'),
  ('a0000000-0000-0000-0000-000000000005', '20000000-0000-0000-0000-000000000005', '推し活仲間限定の特別ボイス', '誕生日プレゼントとして友人にあげたいです。「お誕生日おめでとう、まなみさん」というメッセージで。', 'ボイス', 1000, 3000, now() + interval '3 days', 'open', now() - interval '8 hours');
INSERT INTO auction_bids (auction_id, creator_id, bid_amount, message, estimated_days, created_at) VALUES
  ('a0000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001', 5000, 'お誕生日おめでとうございます🎂 みきさん向けのオリジナル動画を心を込めて作らせていただきます！特別感あるサプライズ仕様で。', 3, now() - interval '1 hours'),
  ('a0000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000003', 3500, '誕生日のお祝い動画、ぜひ作らせてください✨ 衣装やセリフのご希望があれば伺います。スピード納品もOK！', 2, now() - interval '30 minutes'),
  ('a0000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000007', 7000, 'プレミアムプランで作成します🌸 オフショ風の動画にして、メイクからこだわります。', 5, now() - interval '15 minutes'),
  ('a0000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000002', 3000, 'チェキ撮影、お任せください💕 ゆうきさんの好きな雰囲気を教えていただければ調整します。', 4, now() - interval '20 hours'),
  ('a0000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000010', 4500, 'プレミアムチェキ、おすすめです✨ ピンク系・モノクロ系などお好みを伺ってから撮影します。', 3, now() - interval '8 hours'),
  ('a0000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000005', 4000, 'ASMRは得意なジャンルです！耳元で優しく囁くスタイルで作成します。マイクは MV-7 使用。', 4, now() - interval '4 hours'),
  ('a0000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000011', 5500, '大人っぽい囁きスタイルのASMRをご提案します。バイノーラル録音可能。', 3, now() - interval '2 hours'),
  ('a0000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000004', 12000, 'ナースコス得意です！結婚式向けにかわいらしくお祝い感あるトーンで作成いたします🎀', 7, now() - interval '6 hours'),
  ('a0000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000005', 1500, 'まなみさんへのお誕生日メッセージ、心を込めてお作りします🌸', 1, now() - interval '4 hours'),
  ('a0000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000007', 2000, '当日朝までに納品可能です！', 1, now() - interval '2 hours');
